```dart
Future<bool> saveDefaultCity(String city) async {
  if (city.length < 3) {
    return false;
  }
  try {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('defaultCity', city);
    return true;
  } catch (e) {
    print('Erreur de sauvegarde : $e');
    return false;
  }
}
```
